// Structured output: Gemini guarantees JSON — no fragile text parsing
const raw = $input.first().json;
const rawText = raw.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || '{}';

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  parsed = { rewritten_query: 'REWRITE_FAILED', is_greeting: false, detected_language: 'unknown', intent: 'general' };
}

return [{
  json: {
    original_message: $('Rewrite Webhook').first().json.body.message,
    rewritten_query: parsed.rewritten_query || 'REWRITE_FAILED',
    is_greeting: parsed.is_greeting === true,
    detected_language: parsed.detected_language || $('Rewrite Webhook').first().json.body.language || 'auto',
    intent: parsed.intent || 'general',
    channel: $('Rewrite Webhook').first().json.body.channel || 'api',
    timestamp: new Date().toISOString()
  }
}];
